INSERT INTO public.metric_definitions (id, metric_number, name, category, sub_category, release, description, formula, unit, update_frequency, data_owner) VALUES (39, 1, 'Active Projects', 'Portfolio Snapshot', 'Portfolio at a Glance', 'MVP', 'Total count of nxzen (UK & India) active projects', 'COUNT of active projects from the Dynamics Project extract', 'Count (#)', 'Weekly', 'Finance');
INSERT INTO public.metric_definitions (id, metric_number, name, category, sub_category, release, description, formula, unit, update_frequency, data_owner) VALUES (40, 2, 'Active Clients', 'Portfolio Snapshot', 'Portfolio at a Glance', 'MVP', 'Number of distinct (UK & India) clients with at least one active project', 'COUNT DISTINCT (Client) of active projects from the Dynamics Project extract', 'Count (#)', 'Weekly', 'Finance');
INSERT INTO public.metric_definitions (id, metric_number, name, category, sub_category, release, description, formula, unit, update_frequency, data_owner) VALUES (41, 3, 'Overall RAG Status', 'Portfolio Snapshot', 'Portfolio at a Glance', 'MVP', 'Overall RAG status of the portfolio', 'If overall RAG Red %: ≥10% then Red
INSERT INTO public.metric_definitions (id, metric_number, name, category, sub_category, release, description, formula, unit, update_frequency, data_owner) VALUES (42, 4, 'Overall RAG — Red %', 'Portfolio Snapshot', 'Portfolio at a Glance', 'MVP', 'Percentage of active projects with an overall RAG status of Red.', 'COUNT(Overall RAG = Red) / COUNT(Active Projects) × 100', '% (one decimal)', 'Weekly', 'PM (reported), Portfolio Office (validate & consolidate)');
INSERT INTO public.metric_definitions (id, metric_number, name, category, sub_category, release, description, formula, unit, update_frequency, data_owner) VALUES (43, 5, 'Overall RAG — Amber %', 'Portfolio Snapshot', 'Portfolio at a Glance', 'MVP', 'Percentage of active projects with an overall RAG status of Amber.', 'COUNT(Overall RAG = Amber) / COUNT(Active Projects) × 100', '% (one decimal)', 'Weekly', 'PM (reported), Portfolio Office (validate & consolidate)');
INSERT INTO public.metric_definitions (id, metric_number, name, category, sub_category, release, description, formula, unit, update_frequency, data_owner) VALUES (44, 6, 'Overall RAG — Green %', 'Portfolio Snapshot', 'Portfolio at a Glance', 'MVP', 'Percentage of active projects with an overall RAG status of Green.', 'COUNT(Overall RAG = Green) / COUNT(Active Projects) × 100', '% (one decimal)', 'Weekly', 'PM (reported), Portfolio Office (validate & consolidate)');
INSERT INTO public.metric_definitions (id, metric_number, name, category, sub_category, release, description, formula, unit, update_frequency, data_owner) VALUES (45, 7, 'On Time %', 'Portfolio Snapshot', 'Delivery Indicators', 'MVP', 'Measures the next due milestone.  Percentage of active projects tracking on schedule (On schedule RAG: Green = no slippage).', 'COUNT (Next due milestone RAG = Green) / COUNT (Active Projects) × 100', '% (one decimal)', 'Weekly', 'PM (reported), Portfolio Office (validate & consolidate)');
INSERT INTO public.metric_definitions (id, metric_number, name, category, sub_category, release, description, formula, unit, update_frequency, data_owner) VALUES (46, 8, 'Projects Behind Schedule (count)', 'Portfolio Snapshot', 'Delivery Indicators', 'MVP', 'Measures the next due milestone.  Count of active projects where schedule RAG: Red = next due milestone has slipped.', 'COUNT(Next due milestone RAG = Red)', 'Count (#)', 'Weekly', 'PM (reported), Portfolio Office (validate & consolidate)');
INSERT INTO public.metric_definitions (id, metric_number, name, category, sub_category, release, description, formula, unit, update_frequency, data_owner) VALUES (47, 9, 'On Budget %', 'Portfolio Snapshot', 'Delivery Indicators', 'REL 2', 'Percentage of active projects, where forecast cost is in line with approved budget. (Budget RAG: Green = is in line with approved budget).', 'COUNT(Budget RAG = Green) / COUNT(Active Projects) × 100', '% (one decimal)', 'Monthly (minimum)', 'Finance (actuals), PM (forecast)');
INSERT INTO public.metric_definitions (id, metric_number, name, category, sub_category, release, description, formula, unit, update_frequency, data_owner) VALUES (48, 10, 'Projects Over Budget (count)', 'Portfolio Snapshot', 'Delivery Indicators', 'REL 2', 'Count of active projects where forecast cost exceeds approved budget.', 'COUNT (Budget RAG = Red)', 'Count (#)', 'Monthly', 'Finance (actuals), PM (forecast)');
INSERT INTO public.metric_definitions (id, metric_number, name, category, sub_category, release, description, formula, unit, update_frequency, data_owner) VALUES (49, 11, 'Resource Gaps Flagged', 'Portfolio Snapshot', 'Delivery Indicators', 'MVP', 'Count of active projects with a flagged resource gap (Resource RAG = Red or Amber).', 'COUNT(Resource RAG ∈ {Amber, Red})', 'Count (#)', 'Weekly', 'PM (flagged), Portfolio Office (consolidated)');
INSERT INTO public.metric_definitions (id, metric_number, name, category, sub_category, release, description, formula, unit, update_frequency, data_owner) VALUES (50, 12, 'Client Satisfaction Score', 'Portfolio Snapshot', 'Delivery Indicators', 'REL 3', 'Percentage of clients rating project delivery ≥4/5 (or equivalent) in most recent satisfaction check.', 'COUNT(CSAT ≥4) / COUNT(CSAT responses) × 100', '% (one decimal)', 'Monthly / per milestone', 'TBC (a Corporate owner is required)');
INSERT INTO public.metric_definitions (id, metric_number, name, category, sub_category, release, description, formula, unit, update_frequency, data_owner) VALUES (51, 13, 'Utilisation – UK (overall)', 'Resource & Utilisation', 'Overall', 'MVP', 'Percentage of billable & business/practice developmenthours worked against available billable & internal project capacity for UK-based resources.', 'Billable & business/practice development (hours) logged / Available billable & internal project hours (contracted − leave) × 100', '% (one decimal)', 'Weekly', 'Resource Manager / Finance');
INSERT INTO public.metric_definitions (id, metric_number, name, category, sub_category, release, description, formula, unit, update_frequency, data_owner) VALUES (52, 14, 'Utilisation – India (overall)', 'Resource & Utilisation', 'Overall', 'MVP', 'Percentage of billable & business/practice development hours worked against available billable & internal project capacity for India-based resources.', 'Billable & business/practice development (hours) logged / Available billable & internal project hours (contracted − leave) × 100', '% (one decimal)', 'Weekly', 'Resource Manager / India Resource Lead');
INSERT INTO public.metric_definitions (id, metric_number, name, category, sub_category, release, description, formula, unit, update_frequency, data_owner) VALUES (53, 15, 'Utilisation – by Practice (Renewables & Eng)', 'Resource & Utilisation', 'By Practice', 'REL 2', 'Percentage of billable & business/practice development utilisation for resources aligned to the Renewables & Engineering practice/sub-proposition.', 'Billable & ibusiness/practice development hours logged (Renewables & Eng resources) / Available billable hours (same group) × 100', '% (one decimal)', 'Weekly', 'Practice Lead / Resource Manager');
INSERT INTO public.metric_definitions (id, metric_number, name, category, sub_category, release, description, formula, unit, update_frequency, data_owner) VALUES (54, 16, 'Utilisation – by Practice (Data Intelligence & AI)', 'Resource & Utilisation', 'By Practice', 'REL 2', 'Percentage of billable & business/practice development utilisation for resources aligned to the Data Intelligence & AI practice.', 'Billable & business/practice development hours logged (Data Intelligence & AI) / Available billable hours (same group) × 101', '% (one decimal)', 'Weekly', 'Practice Lead / Resource Manager');
INSERT INTO public.metric_definitions (id, metric_number, name, category, sub_category, release, description, formula, unit, update_frequency, data_owner) VALUES (55, 17, 'Utilisation – by Practice (Cyber Security)', 'Resource & Utilisation', 'By Practice', 'REL 2', 'Percentage of billable & business/practice development utilisation for resources aligned to the Cyber Security practice/sub-proposition.', 'Billable & ibusiness/practice development hours logged (Cyber Security resources) / Available billable hours (same group) × 100', '% (one decimal)', 'Weekly', 'Practice Lead / Resource Manager');
INSERT INTO public.metric_definitions (id, metric_number, name, category, sub_category, release, description, formula, unit, update_frequency, data_owner) VALUES (56, 18, 'Utilisation – by Practice (Apps & Development)', 'Resource & Utilisation', 'By Practice', 'REL 2', 'Percentage of billable & business/practice development utilisation for resources aligned to the Aps & Development practice/sub-proposition.', 'Billable & ibusiness/practice development hours logged (Apps & Development resources) / Available billable hours (same group) × 100', '% (one decimal)', 'Weekly', 'Practice Lead / Resource Manager');
INSERT INTO public.metric_definitions (id, metric_number, name, category, sub_category, release, description, formula, unit, update_frequency, data_owner) VALUES (57, 19, 'Utilisation – by Practice (OT)', 'Resource & Utilisation', 'By Practice', 'REL 2', 'Percentage of billable & business/practice development utilisation for resources aligned to the OT practice/sub-proposition.', 'Billable & ibusiness/practice development hours logged (OT resources) / Available billable hours (same group) × 100', '% (one decimal)', 'Weekly', 'Practice Lead / Resource Manager');
INSERT INTO public.metric_definitions (id, metric_number, name, category, sub_category, release, description, formula, unit, update_frequency, data_owner) VALUES (58, 20, 'Unassigned Resources %', 'Resource & Utilisation', 'Capacity', 'MVP', 'Percentage of total UK & India resource headcount currently unassigned to any active project.', 'COUNT(Unassigned FTE excl. Corporate) / Total FTE (excl. Corporate) × 100', '% (one decimal)', 'Weekly', 'Resource Manager');
INSERT INTO public.metric_definitions (id, metric_number, name, category, sub_category, release, description, formula, unit, update_frequency, data_owner) VALUES (59, 21, 'Unbillable Resources %', 'Resource & Utilisation', 'Capacity', 'MVP', 'Percentage of total UK & India hours logged against non-billable codes (internal, bench, training).', 'Non-billable hours (excl. Corporate) / Total logged hours (excl. Corporate) × 100', '% (one decimal)', 'Weekly', 'Finance / Resource Manager');
INSERT INTO public.metric_definitions (id, metric_number, name, category, sub_category, release, description, formula, unit, update_frequency, data_owner) VALUES (60, 22, 'Schedule RAG per Project', 'Delivery Health', 'Project Status', 'MVP', 'Measures the project as a whole. Schedule performance for each active project rated Green/Amber/Red against defined criteria.', 'Green: no slippage; Amber: risk of slippage if no action taken Red project has slipped.', 'RAG (G/A/R)', 'Weekly', 'PM');
INSERT INTO public.metric_definitions (id, metric_number, name, category, sub_category, release, description, formula, unit, update_frequency, data_owner) VALUES (61, 23, 'Target Margin RAG per Project', 'Delivery Health', 'Project Status', 'REL 2', 'Target margin performance for each active project rated against approved budget.', 'Green <2% variance; Amber 2–5% variance; Red >5% variance', 'RAG (G/A/R)', 'Monthly', 'Finance (actuals), PM (forecast)');
INSERT INTO public.metric_definitions (id, metric_number, name, category, sub_category, release, description, formula, unit, update_frequency, data_owner) VALUES (62, 24, 'Resource RAG per Project', 'Delivery Health', 'Project Status', 'MVP', 'Resource health per active project.  RAG: Red = resource issue now / will miss schedule unless action is taken.  Amber = will become a resource problem unless action is taken.
INSERT INTO public.metric_definitions (id, metric_number, name, category, sub_category, release, description, formula, unit, update_frequency, data_owner) VALUES (63, 25, 'Scope RAG per Project', 'Delivery Health', 'Project Status', 'REL 2', 'Scope stability per active project: Green = baseline approved and stable; Amber = changes identified not yet agreed; Red = uncontrolled scope change impacting T/C/Q.', 'PM assessment against agreed scope baseline.', 'RAG (G/A/R)', 'Weekly', 'PM');
INSERT INTO public.metric_definitions (id, metric_number, name, category, sub_category, release, description, formula, unit, update_frequency, data_owner) VALUES (64, 26, 'Open Risks per Project', 'Delivery Health', 'Risks & Issues', 'MVP', 'Count and detail of open risks per active project, categorised by rating and status.', 'COUNT(Risks where Status = Open), grouped by active project and severity.', 'Count + detail', 'Weekly', 'PM');
INSERT INTO public.metric_definitions (id, metric_number, name, category, sub_category, release, description, formula, unit, update_frequency, data_owner) VALUES (65, 27, 'Open Issues per Project', 'Delivery Health', 'Risks & Issues', 'MVP', 'Count and detail of open issues (materialised risks or blockers) per active project.', 'COUNT(Issues where Status = Open), grouped by active project.', 'Count + detail', 'Weekly', 'PM');
INSERT INTO public.metric_definitions (id, metric_number, name, category, sub_category, release, description, formula, unit, update_frequency, data_owner) VALUES (66, 28, 'Total Portfolio Value', 'Commercial', 'Revenue', 'REL 1', 'Sum of contracted value of all active projects.', 'SUM(Contracted Value) across all active projects.', '£ (GBP, thousands)', 'On contract signature (updated monthly)', 'Finance / Client Partner');
INSERT INTO public.metric_definitions (id, metric_number, name, category, sub_category, release, description, formula, unit, update_frequency, data_owner) VALUES (67, 29, 'Revenue Recognised MTD', 'Commercial', 'Revenue', 'REL 1', 'Revenue formally recognised in the current month to date, per accounting policy.', 'SUM(Revenue Recognised) where recognition date in current calendar month.', '£ (GBP, thousands)', 'Monthly', 'Finance');
INSERT INTO public.metric_definitions (id, metric_number, name, category, sub_category, release, description, formula, unit, update_frequency, data_owner) VALUES (68, 30, 'Revenue vs Plan Variance', 'Commercial', 'Revenue', 'REL 1', 'Difference between actual revenue recognised MTD and planned revenue for the month.', 'Revenue Recognised MTD − Revenue Plan MTD. Show as £ and %.', '£ and %', 'Monthly (ideally weekly)', 'Finance');
INSERT INTO public.metric_definitions (id, metric_number, name, category, sub_category, release, description, formula, unit, update_frequency, data_owner) VALUES (69, 31, 'Average Project Margin %', 'Commercial', 'Margin', 'REL 1', 'Average gross margin across all active projects (revenue minus direct delivery cost).', 'AVERAGE(Project Margin %) where Margin = (Revenue − Direct Costs) / Revenue × 100.', '% (one decimal)', 'Monthly', 'Finance');
INSERT INTO public.metric_definitions (id, metric_number, name, category, sub_category, release, description, formula, unit, update_frequency, data_owner) VALUES (70, 32, 'Billable Utilisation %', 'Commercial', 'Margin', 'MVP', 'Percentage of total logged hours that are billable to a client — commercial lens on utilisation.', 'Billable hours / Total hours logged (excl. Corporate) × 100 (all resources, UK + India).', '% (one decimal)', 'Weekly', 'Finance / Resource Manager');
INSERT INTO public.metric_definitions (id, metric_number, name, category, sub_category, release, description, formula, unit, update_frequency, data_owner) VALUES (71, 33, 'Win Rate (6-month rolling)', 'Commercial', 'Pipeline', 'REL 2', 'Percentage of pitched opportunities won in the rolling 6-month window.', 'COUNT(Opportunities Won) / COUNT(Opportunities Pitched) × 100 over rolling 6 months.', '% (one decimal)', 'Monthly', 'Client Partner / Growth team (Mike Farrell)');
INSERT INTO public.metric_definitions (id, metric_number, name, category, sub_category, release, description, formula, unit, update_frequency, data_owner) VALUES (72, 34, 'Pipeline Value', 'Commercial', 'Pipeline', 'REL 2', 'Total value of opportunities currently in pipeline from Prospect to Negotiation stage.', 'SUM(Opportunity Value) where Stage ∈ {Prospect, Qualified, Proposal, Negotiation}.', '£ (GBP, thousands)', 'Weekly', 'Client Partner / Growth team (Mike Farrell)');
INSERT INTO public.metric_definitions (id, metric_number, name, category, sub_category, release, description, formula, unit, update_frequency, data_owner) VALUES (73, 35, 'Repeat Business Rate %', 'Commercial', 'Pipeline', 'REL 2', 'Percentage of revenue (or active projects) in the current period derived from existing clients (re-contracted or extended).', 'Revenue (or active projects) from existing clients (renewed/extended) / Total Revenue × 100.', '% (one decimal)', 'Monthly', 'Client Partner');
INSERT INTO public.metric_definitions (id, metric_number, name, category, sub_category, release, description, formula, unit, update_frequency, data_owner) VALUES (74, 36, 'Average Days to Contract', 'Commercial', 'Pipeline', 'REL 2', 'Average number of calendar days from opportunity creation/bid submission to signed contract.', 'AVERAGE(Contract Signed Date − Opportunity Created/Bid Submitted Date) across deals closed in period.', 'Days (whole number .5 or > rolled up)', 'Monthly', 'Client Partner / Legal');
INSERT INTO public.metric_definitions (id, metric_number, name, category, sub_category, release, description, formula, unit, update_frequency, data_owner) VALUES (75, 37, 'Planned vs Actual Invoicing', 'Commercial', 'Invoicing', 'REL 3', 'Variance between the invoices planned to be raised in the period and the invoices actually raised. Measures billing discipline and cash flow predictability.', 'Planned Invoice Value (period) − Actual Invoice Value (period). Express as £ variance and % variance: (Actual − Plan) / Plan × 100. Report at project level and portfolio total.', '£ (GBP) and % variance — shown per project and portfolio total', 'Monthly', 'Finance');
INSERT INTO public.metric_definitions (id, metric_number, name, category, sub_category, release, description, formula, unit, update_frequency, data_owner) VALUES (76, 38, 'Gross Margin £ (per project and portfolio)', 'Commercial', 'Margin', 'REL 1', 'Absolute gross margin in pounds (£) for each active project and the portfolio total. Gross margin = Revenue − Direct Delivery Cost. Complements metric #28 (Average Project Margin %) by providing the £ value, enabling prioritisation by commercial impact rather than percentage alone. A project with a high margin % but low £ value may be less commercially significant than a lower-% but higher-value project.', 'Gross Margin £ = Revenue Recognised − Direct Delivery Cost. Direct Delivery Cost = Labour Cost (billable hours × cost rate) + Direct Expenses (travel, subcontractors, software, etc.). Portfolio Gross Margin £ = SUM(Gross Margin £) across all active projects. Gross Margin % (cross-reference) = Gross Margin £ / Revenue Recognised × 100.', '£ (GBP, thousands) — shown per project; portfolio total; with Gross Margin % alongside', 'Monthly', 'Finance');
INSERT INTO public.metric_definitions (id, metric_number, name, category, sub_category, release, description, formula, unit, update_frequency, data_owner) VALUES (77, 39, 'Escalations and decisions required per project', 'Delivery Health', 'Project Status', 'MVP', 'All escalations and decisions required per project, monitored on a weekly basis', 'All escalations and decisions required per project, monitored on a weekly basis', 'Free text', 'Weekly', 'PM');
INSERT INTO public.metric_definitions (id, metric_number, name, category, sub_category, release, description, formula, unit, update_frequency, data_owner) VALUES (78, 40, 'Cost RAG per project', 'Delivery Health', 'Project Status', 'REL 3', 'Measures the project as a whole in terms of whether the forecast cost is in line with approved budget. (Budget RAG: Green = is in line with approved budget).', 'Red: project is over budget.  Amber: project at risk of going over budget unless action is taken.  Green = not over budget & not at risk of going over.', 'RAG (G/A/R)', 'Weekly', 'PM');
INSERT INTO public.metric_definitions (id, metric_number, name, category, sub_category, release, description, formula, unit, update_frequency, data_owner) VALUES (79, 41, 'Deals > 4 months in the pipeline', 'Commercial', 'Pipeline', 'REL 3', 'Count of all on going deals (not yet been won) which have been in the pipeline for over 4 months', 'COUNT(Ongoing deals in the pipeline over 4 months)', 'Count + detail', 'Weekly', 'Client Partner');
